function maxProduct(nums) {
  if (nums.length === 0) return 0;

  let res = nums[0];
  let curMin = 1;
  let curMax = 1;

  for (const n of nums) {
    const tmp = curMax * n;
    curMax = Math.max(n * curMax, n * curMin, n);
    curMin = Math.min(tmp, n * curMin, n);
    res = Math.max(res, curMax);
  }

  return res;
}

